SELECT MAX(date_recorded) AS latest_score_date
FROM performance_scores
WHERE engine_id = 1;

SELECT score
FROM engine_performance
WHERE engine_id = 0;

SELECT COUNT(*) AS total_events
FROM (
  SELECT change_id FROM performance_changes WHERE engine_id = 1
  UNION ALL
  SELECT alert_id FROM performance_alerts WHERE engine_id = 1
) AS combined_events;

SELECT engine_name 
FROM database_engines 
ORDER BY engine_name;

SELECT MAX(score) AS max_score
FROM engine_performance
WHERE engine_id = 0 AND environment = 'staging';
